 using System.ComponentModel;
 using System.Text.Json;
 using System.Text.RegularExpressions;
 using Microsoft.Agents.AI;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // --- Configuration ---
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable to run this agent.");

 var topic = args.Length > 0
     ? string.Join(' ', args)
     : PromptForTopic();

 Console.WriteLine($"\n🔍 Researching: {topic}\n");

 // --- Note-taking state ---
 var notes = new List<(string Title, string Content)>();

 // --- Define tools ---
 [Description("Search the web for information on a topic. Returns article titles and text snippets.")]
 async Task<string> SearchWeb(
     [Description("The search query")] string query)
 {
     Console.WriteLine($"  🌐 Searching: \"{query}\"");

     using var http = new HttpClient();
     http.DefaultRequestHeaders.Add("User-Agent", "ResearchAgent/1.0");

     var encoded = Uri.EscapeDataString(query);
     var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search"
             + $"&srsearch={encoded}&format=json&srlimit=5&utf8=1";
     try
     {
         var json = await http.GetStringAsync(url);
         using var doc = JsonDocument.Parse(json);
         var results = doc.RootElement.GetProperty("query").GetProperty("search");

         var snippets = new List<string>();
         foreach (var item in results.EnumerateArray())
         {
             var title = item.GetProperty("title").GetString();
             var snippet = Regex.Replace(
                 item.GetProperty("snippet").GetString() ?? "", "<.*?>", string.Empty);
             snippets.Add($"• {title}: {snippet}");
         }

         return snippets.Count > 0
             ? $"Results for \"{query}\":\n\n{string.Join("\n\n", snippets)}"
             : $"No results found for \"{query}\".";
     }
     catch (Exception ex)
     {
         return $"Search failed: {ex.Message}";
     }
 }

 [Description("Save a research note with a title and content for later reference.")]
 string SaveNote(
     [Description("Short title for the note")] string title,
     [Description("Detailed note content")] string content)
 {
     notes.Add((title, content));
     Console.WriteLine($"  📝 Note saved: \"{title}\"");
     return $"Note #{notes.Count} saved: \"{title}\"";
 }

 [Description("Retrieve all saved research notes to compile findings.")]
 string GetNotes()
 {
     Console.WriteLine($"  📋 Retrieving {notes.Count} note(s)");
     if (notes.Count == 0) return "No notes saved yet.";
     return string.Join("\n\n---\n\n",
         notes.Select((n, i) => $"[Note #{i + 1}] {n.Title}\n{n.Content}"));
 }

 var tools = new AITool[]
 {
     AIFunctionFactory.Create(SearchWeb),
     AIFunctionFactory.Create(SaveNote),
     AIFunctionFactory.Create(GetNotes),
 };

 // --- Build the chat client with function-invocation middleware ---
 IChatClient innerClient = new OpenAIClient(apiKey)
     .GetChatClient("gpt-4o-mini-2024-07-18")
     .AsIChatClient();

 // --- Create the agent ---
 var agent = new ChatClientAgent(
     innerClient,
     name: "ResearchAgent",
     description: "An agent that researches topics by searching the web and taking notes.",
     instructions: """
         You are a thorough research agent. Your goal is to investigate a topic using the
         available tools and produce a well-organized summary.

         Follow this workflow:
         1. Search for the main topic to get a broad overview.
         2. Perform 2-3 additional searches on specific subtopics or key terms you discover.
         3. After each search, save the most important findings as a note using the save_note tool.
         4. Once you have gathered enough information, retrieve all your notes with get_notes.
         5. Produce a final, comprehensive summary organized into clear sections with key facts.

         Be thorough but concise. Always ground your summary in the search results you found.
         """,
     tools: tools);

 // --- Run the agent ---
 Console.WriteLine("Agent is working...\n");

 var session = await agent.CreateSessionAsync();
 var response = await agent.RunAsync(
     $"Please research the following topic and provide a comprehensive summary: {topic}",
     session);

 Console.WriteLine("\n═══════════════════════════════════════════════");
 Console.WriteLine("  RESEARCH SUMMARY");
 Console.WriteLine("═══════════════════════════════════════════════\n");
 Console.WriteLine(response.Text);
 Console.WriteLine("\n═══════════════════════════════════════════════");
 Console.WriteLine($"  Notes collected: {notes.Count}");
 Console.WriteLine("═══════════════════════════════════════════════");

 // --- Helpers ---
 static string PromptForTopic()
 {
     Console.Write("Enter a research topic: ");
     var input = Console.ReadLine()?.Trim();
     return string.IsNullOrEmpty(input) ? "Quantum Computing" : input;
 }
